import React from 'react'
import type { UseOverlayReturnOptions } from '@fs/zion-ui'
import { Paragraph, Button, DialogOverlay, DialogOverlayActions, DialogOverlayFooter } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import type { Gender } from '@fs/zion-tree-types'
import { NoticeLoading } from '@fs/zion-icon'

type Props = {
  personName: string
  personGender: Gender | undefined
  overlay: UseOverlayReturnOptions
  loading: boolean
}

export default function DoubleCheckPersonIsDeceasedDialog({
  personName,
  personGender,
  overlay,
  loading,
}: Props): JSX.Element {
  const [t] = useTranslation()

  return (
    <DialogOverlay {...overlay} title={t('conclusion.are-you-sure-this-person-is-deceased.heading')}>
      <Paragraph size="sm">
        {t('conclusion.is-this-person-deceased.description', { personName, gender: personGender ?? 'UNKNOWN' })}
      </Paragraph>

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button data-testid="person-deceased:cancel-action" onClick={overlay.close}>
            {t('common-ui:cancel.action')}
          </Button>
          <Button
            type="submit"
            form="conclusion-form"
            emphasis="high"
            disabled={loading}
            data-testid="person-deceased:submit:button"
            Icon={loading ? NoticeLoading : undefined}
          >
            {t('conclusion.yes-save.action')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
